mapper.select:
SELECT ROW_NUMBER() OVER(ORDER BY (p.product_info ->> 'sort_order')::int DESC NULLS LAST, p.created_at DESC NULLS LAST, p.product_id) AS row_num , p.product_id , p.product_cd , p.product_nm , p.product_type , (SELECT u.unit_cd FROM om_product_unit u WHERE u.product_id = p.product_id AND u.is_base_unit = true LIMIT 1) AS base_unit_cd , p.is_sale , p.is_display , p.created_by , TO_CHAR(p.created_at, 'YYYY-MM-DD HH24:MI:SS') AS created_at FROM om_product_m p WHERE p.is_deleted = false
AND p.corporation_cd = #{corporationCd}
ORDER BY (p.product_info ->> 'sort_order')::int DESC NULLS LAST, p.created_at DESC NULLS LAST, p.product_id

SELECT p.product_id , p.corporation_cd , p.product_cd , p.product_nm , p.product_type , p.sale_price , p.stock_qty , p.is_gift , p.is_sale , p.is_display , (SELECT u.unit_cd FROM om_product_unit u WHERE u.product_id = p.product_id AND u.is_base_unit = true LIMIT 1) AS base_unit_cd , p.product_info ->> 'product_en_nm' AS product_en_nm , p.product_info ->> 'category_cd' AS category_cd , p.product_info ->> 'brand_cd' AS brand_cd , (p.product_info ->> 'cost_price')::numeric AS cost_price , (p.product_info ->> 'supply_price')::numeric AS supply_price , p.product_info ->> 'tax_type' AS tax_type , (p.product_info ->> 'safety_stock_qty')::int AS safety_stock_qty , (p.product_info ->> 'min_order_qty')::int AS min_order_qty , (p.product_info ->> 'max_order_qty')::int AS max_order_qty , (p.product_info ->> 'sort_order')::int AS sort_order , p.product_info ->> 'description' AS description , p.product_info ->> 'image_url' AS image_url , p.product_info ->> 'remark' AS remark , TO_CHAR(p.created_at, 'YYYY-MM-DD HH24:MI:SS') AS created_at , TO_CHAR(p.updated_at, 'YYYY-MM-DD HH24:MI:SS') AS updated_at , p.created_by , p.updated_by FROM om_product_m p WHERE p.is_deleted = false
AND p.corporation_cd = #{corporationCd}
ORDER BY (p.product_info ->> 'sort_order')::int DESC NULLS LAST, p.created_at DESC NULLS LAST, p.product_id

mapper.update:
UPDATE om_product_m
   SET updated_at = CURRENT_TIMESTAMP
     , updated_by = #{updatedBy}


             , product_cd = #{value}


             , product_nm = #{value}


             , product_type = #{value}


             , is_sale = #{value}


             , is_display = #{value}


 WHERE product_id = #{productId}
   AND is_deleted = false

UPDATE om_product_m
   SET updated_at = CURRENT_TIMESTAMP
     , updated_by = #{updatedBy}
     , product_cd = #{req.productCd}
     , product_nm = #{req.productNm}
     , product_type = #{req.productType}
     , is_sale = #{req.isSale}
     , is_display = #{req.isDisplay}

     , product_info = (
         (COALESCE(product_info, '{}'::jsonb) - 'units' - 'set_components')
         || jsonb_build_object('product_en_nm', #{req.productEnNm}::text)
         || jsonb_build_object('category_cd', #{req.categoryCd}::text)
         || jsonb_build_object('brand_cd', #{req.brandCd}::text)
         || jsonb_build_object('cost_price', (#{req.costPrice})::numeric)
         || jsonb_build_object('supply_price', (#{req.supplyPrice})::numeric)
         || jsonb_build_object('tax_type', #{req.taxType}::text)
         || jsonb_build_object('safety_stock_qty', (#{req.safetyStockQty})::int)
         || jsonb_build_object('min_order_qty', (#{req.minOrderQty})::int)
         || jsonb_build_object('max_order_qty', (#{req.maxOrderQty})::int)

         || jsonb_build_object('description', #{req.description}::text)
         || jsonb_build_object('image_url', #{req.imageUrl}::text)
         || jsonb_build_object('remark', #{req.remark}::text)
     )
 WHERE product_id = #{productId}
   AND is_deleted = false
